import React, { useState, useEffect, useRef } from 'react';
import { SearchOption, OptionConfig } from './types';
import { BookOpenIcon, GlobeAltIcon, PhotoIcon, ChatBubbleLeftRightIcon, PlayCircleIcon, SparklesIcon } from './components/icons';
import SearchBar from './components/SearchBar';
import { GoogleGenAI } from "@google/genai";

const SEARCH_OPTIONS: OptionConfig[] = [
  { 
    id: SearchOption.AI, 
    title: 'AI Insight', 
    urlTemplate: 'https://www.perplexity.ai/search?q={query}',
    icon: (props) => <SparklesIcon {...props} className="h-6 w-6" />
  },
  { 
    id: SearchOption.Research, 
    title: 'Research', 
    urlTemplate: 'https://scholar.google.com/scholar?q={query}',
    icon: (props) => <BookOpenIcon {...props} className="h-6 w-6" />
  },
  { 
    id: SearchOption.Forums, 
    title: 'Discussions', 
    urlTemplate: 'https://www.google.com/search?udm=18&q={query}',
    icon: (props) => <ChatBubbleLeftRightIcon {...props} className="h-6 w-6" />
  },
  { 
    id: SearchOption.YouTube, 
    title: 'Videos', 
    urlTemplate: 'https://www.youtube.com/results?search_query={query}',
    icon: (props) => <PlayCircleIcon {...props} className="h-6 w-6" />
  },
  { 
    id: SearchOption.Images, 
    title: 'Images', 
    urlTemplate: 'https://www.google.com/search?tbm=isch&q={query}',
    icon: (props) => <PhotoIcon {...props} className="h-6 w-6" />
  },
  { 
    id: SearchOption.Domain, 
    title: 'Knowledge', 
    urlTemplate: 'https://www.google.com/search?q={query}&udm=14',
    icon: (props) => <GlobeAltIcon {...props} className="h-6 w-6" />
  },
];

interface ColumnResult {
  id: SearchOption;
  content: string;
  sources: { title: string; uri: string }[];
  loading: boolean;
  error?: string;
}

export default function App() {
  const [query, setQuery] = useState<string>('');
  const [isSearching, setIsSearching] = useState(false);
  const [results, setResults] = useState<Record<SearchOption, ColumnResult>>(
    SEARCH_OPTIONS.reduce((acc, opt) => {
      acc[opt.id] = { id: opt.id, content: '', sources: [], loading: false };
      return acc;
    }, {} as Record<SearchOption, ColumnResult>)
  );

  const fetchCategoryResult = async (option: OptionConfig, searchQuery: string) => {
    setResults(prev => ({
      ...prev,
      [option.id]: { ...prev[option.id], loading: true, content: '', sources: [] }
    }));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Perform a specific search focused on "${option.title}" for the query: "${searchQuery}". 
      If it's Research, focus on academic facts. If Forums, focus on community sentiment. 
      If AI Insight, provide a comprehensive answer. If Videos, describe what kind of video content exists.
      Return a concise summary (2-3 paragraphs max) and key findings.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      const text = response.text || "No results found.";
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const sources = groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({
          title: chunk.web.title,
          uri: chunk.web.uri
        }));

      setResults(prev => ({
        ...prev,
        [option.id]: { ...prev[option.id], loading: false, content: text, sources }
      }));
    } catch (error) {
      console.error(`Error fetching ${option.id}:`, error);
      setResults(prev => ({
        ...prev,
        [option.id]: { ...prev[option.id], loading: false, error: 'Failed to fetch results.' }
      }));
    }
  };

  const handleSearchSubmit = (submittedQuery: string) => {
    setQuery(submittedQuery);
    setIsSearching(true);
    window.location.hash = `q=${encodeURIComponent(submittedQuery)}`;

    // Trigger searches for all categories
    SEARCH_OPTIONS.forEach(option => {
      fetchCategoryResult(option, submittedQuery);
    });
  };

  useEffect(() => {
    const hash = window.location.hash.substring(1);
    const params = new URLSearchParams(hash);
    const initialQuery = params.get('q');
    if (initialQuery) {
      handleSearchSubmit(initialQuery);
    }
  }, []);

  const resetSearch = () => {
    setQuery('');
    setIsSearching(false);
    window.location.hash = '';
  };

  return (
    <main className="min-h-screen bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-slate-100 transition-colors duration-300">
      {/* Header / Search Bar Section */}
      <div className={`transition-all duration-700 ease-in-out flex flex-col items-center justify-center ${isSearching ? 'py-6 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md sticky top-0 z-50' : 'min-h-[60vh]'}`}>
        <div className="w-full max-w-4xl px-4 flex flex-col items-center">
          <h1 
            onClick={resetSearch}
            className={`cursor-pointer font-bold tracking-tight text-transparent bg-clip-text bg-gradient-to-r from-indigo-500 to-purple-500 transition-all duration-500 ${isSearching ? 'text-2xl mb-4' : 'text-6xl md:text-7xl mb-6'}`}
          >
            Searchify
          </h1>
          {!isSearching && (
            <p className="text-lg text-slate-600 dark:text-slate-400 mb-8 text-center max-w-xl animate-fade-in">
              The ultimate multi-destination search engine. See everything in one place.
            </p>
          )}
          <SearchBar onSearch={handleSearchSubmit} initialQuery={query} />
        </div>
      </div>

      {/* Dashboard Columns Section */}
      {isSearching && (
        <div className="p-4 md:p-6 lg:p-8 overflow-x-auto">
          <div className="flex flex-nowrap md:grid md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-6 min-w-max md:min-w-0">
            {SEARCH_OPTIONS.map((option) => {
              const res = results[option.id];
              return (
                <div 
                  key={option.id} 
                  className="flex flex-col w-[300px] md:w-full min-h-[500px] bg-white dark:bg-slate-900 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-800 overflow-hidden transform transition-all duration-300 hover:shadow-2xl hover:-translate-y-1"
                >
                  {/* Column Header */}
                  <div className="p-4 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <div className="text-indigo-500">
                        <option.icon />
                      </div>
                      <h2 className="font-bold text-sm uppercase tracking-wider text-slate-500 dark:text-slate-400">
                        {option.title}
                      </h2>
                    </div>
                    <a 
                      href={option.urlTemplate.replace('{query}', encodeURIComponent(query))} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="text-xs text-indigo-500 hover:text-indigo-600 font-semibold"
                    >
                      Full Search
                    </a>
                  </div>

                  {/* Column Content */}
                  <div className="flex-1 p-4 overflow-y-auto custom-scrollbar">
                    {res.loading ? (
                      <div className="space-y-4 animate-pulse">
                        <div className="h-4 bg-slate-200 dark:bg-slate-800 rounded w-3/4"></div>
                        <div className="h-4 bg-slate-200 dark:bg-slate-800 rounded w-full"></div>
                        <div className="h-4 bg-slate-200 dark:bg-slate-800 rounded w-5/6"></div>
                        <div className="h-20 bg-slate-200 dark:bg-slate-800 rounded w-full"></div>
                      </div>
                    ) : res.error ? (
                      <div className="text-red-500 text-sm py-4 text-center">
                        {res.error}
                      </div>
                    ) : (
                      <div className="prose prose-sm dark:prose-invert max-w-none">
                        <p className="whitespace-pre-wrap text-sm leading-relaxed text-slate-700 dark:text-slate-300">
                          {res.content}
                        </p>

                        {res.sources.length > 0 && (
                          <div className="mt-6">
                            <h3 className="text-xs font-bold uppercase text-slate-400 mb-2">Sources</h3>
                            <ul className="space-y-2">
                              {res.sources.slice(0, 3).map((source, i) => (
                                <li key={i}>
                                  <a 
                                    href={source.uri} 
                                    target="_blank" 
                                    rel="noopener noreferrer"
                                    className="text-xs text-indigo-400 hover:underline block truncate"
                                    title={source.title}
                                  >
                                    {source.title || source.uri}
                                  </a>
                                </li>
                              ))}
                            </ul>
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Empty State */}
      {!isSearching && (
        <div className="fixed bottom-0 left-0 right-0 p-8 flex justify-center opacity-30">
          <div className="grid grid-cols-6 gap-8">
            {SEARCH_OPTIONS.map(opt => (
              <div key={opt.id} className="text-slate-400"><opt.icon /></div>
            ))}
          </div>
        </div>
      )}

      <style dangerouslySetInnerHTML={{ __html: `
        .custom-scrollbar::-webkit-scrollbar {
          width: 4px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 10px;
        }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #334155;
        }
        @keyframes fade-in-up {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .animate-fade-in {
          animation: fade-in-up 1s ease-out forwards;
        }
      `}} />
    </main>
  );
}

import React, { useState, useEffect } from 'react';

interface SearchBarProps {
  onSearch: (query: string) => void;
  initialQuery?: string;
}

const SearchBar: React.FC<SearchBarProps> = ({ onSearch, initialQuery = '' }) => {
  const [inputValue, setInputValue] = useState(initialQuery);

  useEffect(() => {
    setInputValue(initialQuery);
  }, [initialQuery]);

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (inputValue.trim()) {
      onSearch(inputValue.trim());
    }
  };

  return (
    <form onSubmit={handleSubmit} className="w-full max-w-2xl group">
      <div className="relative">
        <div className="absolute inset-y-0 left-0 flex items-center pl-4">
          <svg className="h-5 w-5 text-indigo-400 group-focus-within:text-indigo-500 transition-colors" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-5.197-5.197m0 0A7.5 7.5 0 105.196 5.196a7.5 7.5 0 0010.607 10.607z" />
          </svg>
        </div>
        <input
          type="search"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          autoFocus={!initialQuery}
          className="block w-full rounded-2xl border-0 bg-white dark:bg-slate-800 py-4 pl-12 pr-12 text-slate-900 dark:text-slate-100 shadow-xl ring-1 ring-inset ring-slate-200 dark:ring-slate-700 placeholder:text-slate-400 focus:ring-2 focus:ring-inset focus:ring-indigo-500 sm:text-lg transition-all duration-300 group-hover:ring-slate-300 dark:group-hover:ring-slate-600"
          placeholder="What do you want to explore?"
          aria-label="Global search input"
        />
        <div className="absolute inset-y-0 right-0 flex items-center pr-3">
          <kbd className="hidden sm:inline-flex items-center rounded border border-slate-200 dark:border-slate-700 px-1 font-sans text-xs text-slate-400">
            ENTER
          </kbd>
        </div>
      </div>
    </form>
  );
};

export default SearchBar;

