interface ColumnResult {
  id: SearchOption;
  content: string;
  sources: { title: string; uri: string }[];
  image?: string; // Base64 for AI generated image
  loading: boolean;
  error?: string;
}

export default function App() {
  const [query, setQuery] = useState<string>('');
  const [isSearching, setIsSearching] = useState(false);
  const [results, setResults] = useState<Record<SearchOption, ColumnResult>>(
    SEARCH_OPTIONS.reduce((acc, opt) => {
      acc[opt.id] = { id: opt.id, content: '', sources: [], loading: false };
      return acc;
    }, {} as Record<SearchOption, ColumnResult>)
  );

  const fetchCategoryResult = async (option: OptionConfig, searchQuery: string) => {
    setResults(prev => ({
      ...prev,
      [option.id]: { ...prev[option.id], loading: true, content: '', sources: [], image: undefined }
    }));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Step 1: Get Text/Search Results
      const searchPrompt = `Perform a specific search focused on "${option.title}" for the query: "${searchQuery}". 
      If it's Research, focus on academic facts. If Forums, focus on community sentiment. 
      If AI Insight, provide a comprehensive answer. If Videos, describe relevant visual content found.
      If Visuals, provide a summary of what users usually look for with this query.
      Return a concise summary (1-2 paragraphs).`;

      const searchResponse = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: searchPrompt,
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      const text = searchResponse.text || "No results found.";
      const groundingChunks = searchResponse.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const sources = groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({
          title: chunk.web.title,
          uri: chunk.web.uri
        }));

      // Step 2: If it's the "Images" column, generate a visual header
      let generatedImage = undefined;
      if (option.id === SearchOption.Images) {
        try {
          const imageGenResponse = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: `A cinematic, high-quality visual representation of: "${searchQuery}". Artistic, detailed, and relevant.`,
            config: { imageConfig: { aspectRatio: "16:9" } }
          });

          const imagePart = imageGenResponse.candidates?.[0]?.content?.parts.find(p => p.inlineData);
          if (imagePart?.inlineData) {
            generatedImage = `data:image/png;base64,${imagePart.inlineData.data}`;
          }
        } catch (imgErr) {
          console.warn("Image generation skipped or failed:", imgErr);
        }
      }

      setResults(prev => ({
        ...prev,
        [option.id]: { 
          ...prev[option.id], 
          loading: false, 
          content: text, 
          sources, 
          image: generatedImage 
        }
      }));
    } catch (error) {
      console.error(`Error fetching ${option.id}:`, error);
      setResults(prev => ({
        ...prev,
        [option.id]: { ...prev[option.id], loading: false, error: 'Request failed.' }
      }));
